# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import uuid
import json

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = {}

    async def trade_item(self, other_player, item_id, quantity):
        if item_id in self.inventory and item_id not in other_player.inventory:
            if self.inventory[item_id] >= quantity:
                other_player.inventory[item_id] = quantity
                self.inventory[item_id] -= quantity
                await asyncio.sleep(0.1)  # simulate async IO operation
                return True
        return False

class Item:
    def __init__(self, item_id, name):
        self.item_id = item_id
        self.name = name

class GameServer:
    def __init__(self):
        self.players = {}
        self.items = {}

    async def handle_client(self, websocket):
        await self.register_player(websocket)

        while True:
            try:
                message = await websocket.recv()
                data = json.loads(message)
                action = data['action']

                if action == 'request_items':
                    items = [(item.item_id, item.name) for item in self.items.values()]
                    await websocket.send(json.dumps({'items': items}))
                elif action == 'trade_item':
                    item_id = data['item_id']
                    quantity = data['quantity']
                    other_player_name = data['other_player_name']

                    other_player = self.players[other_player_name]
                    if await other_player.trade_item(self, item_id, quantity):
                        await websocket.send(json.dumps({'message': f'Trading {quantity}x {item_id} to {other_player_name} successful!'}))
                    else:
                        await websocket.send(json.dumps({'message': 'Trading failed!'}))

                elif action == 'update_inventory':
                    inventory = data['inventory']
                    self.players[websocket.id].inventory = inventory
            except Exception as e:
                print(f'Error handling client: {str(e)}')
                break

    async def register_player(self, websocket):
        player_name = await self.get_player_name(websocket)
        player_id = str(uuid.uuid4())
        player = Player(player_name)
        self.players[player_id] = player
        await websocket.send(json.dumps({'message': f'Welcome to the game, {player_name}!'}))

    async def get_player_name(self, websocket):
        while True:
            try:
                message = await websocket.recv()
                data = json.loads(message)
                return data['name']
            except Exception as e:
                print(f'Error getting player name: {str(e)}')

async def main():
    game_server = GameServer()

    async with websockets.serve(game_server.handle_client, 'localhost', 8765):
        await asyncio.Future()  # run forever

if __name__ == '__main__':
    asyncio.run(main())